gen-control.c:script:
const valueProp = dispMeta?.id || 'status';
const labelProp = propMeta?.['graphql:labelProp'] || (valueProp + '_label');
return {
    type: "tpl",
    tpl: '<span class="label label-${' + valueProp
        + " == 'ACTIVE' ? 'success' : 'default'}\">"
        + "${" + labelProp + "}</span>"
};

return {
    type: 'switch',
    name: 'status',
    trueValue: 'ACTIVE',
    falseValue: 'INACTIVE',
    onEvent: {
        change: {
            actions: [
                {
                    actionType: 'dialog',
                    condition: "${status == 'INACTIVE'}",
                    dialog: {
                        title: '停用确认',
                        body: '停用后该往来单位不可在新单据中选择，是否继续？',
                        actions: [
                            {
                                type: 'button',
                                actionType: 'ajax',
                                label: '确认停用',
                                api: '@mutation:ErpMdPartner__update/id?id=$id',
                                data: { status: 'INACTIVE' },
                                close: true
                            },
                            {
                                type: 'button',
                                actionType: 'close',
                                label: '取消'
                            }
                        ]
                    }
                }
            ]
        }
    }
};

return {
    type: 'input-text',
    name: 'code',
    required: true,
    onEvent: {
        blur: {
            actions: [
                {
                    actionType: 'ajax',
                    api: {
                        method: 'post',
                        url: '/graphql',
                        dataType: 'raw',
                        data: {
                            query: '${"query{ErpMdPartner__isCodeUnique(code:\"" + code + "\",excludeId:" + (id || "null") + "){v}}"}'
                        },
                        responseType: 'response',
                        adapt: 'function(payload){ var ok = payload && payload.data && payload.data.ErpMdPartner__isCodeUnique === true; return { status: ok ? 0 : 500, msg: ok ? "" : "编码已存在" }; }'
                    }
                }
            ]
        }
    }
};

return {
    type: 'switch',
    name: 'status',
    trueValue: 'ACTIVE',
    falseValue: 'INACTIVE',
    onEvent: {
        change: {
            actions: [
                {
                    actionType: 'dialog',
                    condition: "${status == 'INACTIVE'}",
                    dialog: {
                        title: '停用确认',
                        body: '停用后该往来单位不可在新单据中选择，是否继续？',
                        actions: [
                            {
                                type: 'button',
                                actionType: 'ajax',
                                label: '确认停用',
                                api: '@mutation:ErpMdPartner__update/id?id=$id',
                                data: { status: 'INACTIVE' },
                                close: true
                            },
                            {
                                type: 'button',
                                actionType: 'close',
                                label: '取消'
                            }
                        ]
                    }
                }
            ]
        }
    }
};

return {
    type: 'input-text',
    name: 'code',
    required: true,
    onEvent: {
        blur: {
            actions: [
                {
                    actionType: 'ajax',
                    api: {
                        method: 'post',
                        url: '/graphql',
                        dataType: 'raw',
                        data: {
                            query: '${"query{ErpMdPartner__isCodeUnique(code:\"" + code + "\",excludeId:" + (id || "null") + "){v}}"}'
                        },
                        responseType: 'response',
                        adapt: 'function(payload){ var ok = payload && payload.data && payload.data.ErpMdPartner__isCodeUnique === true; return { status: ok ? 0 : 500, msg: ok ? "" : "编码已存在" }; }'
                    }
                }
            ]
        }
    }
};
